import sys
import math

class Solution:
    def primeFactorisation(self, n: int) -> str:
        factors = []
        i = 2
        while i * i <= n:
            count = 0
            while n % i == 0:
                n //= i
                count += 1
            if count > 0:
                if count == 1:
                    factors.append(str(i))
                else:
                    factors.append(str(i) + '^' + str(count))
            i += 1
        if n > 1:
            factors.append(str(n))
        return ' * '.join(factors)

if __name__ == '__main__':
