#include <numeric>

#include <iostream>
#include <vector>
#include <string>

class Solution {
public:
    std::string primeFactorisation(long long n) {
        std::vector<std::string> factors;
        long long i = 2;
        while (i * i <= n) {
            long long count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            if (count > 0) {
                if (count == 1) {
                    factors.push_back(std::to_string(i));
                } else {
                    factors.push_back(std::to_string(i) + "^" + std::to_string(count));
                }
            }
            i++;
        }
        if (n > 1) {
            factors.push_back(std::to_string(n));
        }
        std::string result;
        for (size_t i = 0; i < factors.size(); i++) {
            result += factors[i];
            if (i < factors.size() - 1) {
                result += " * ";
            }
        }
        return result;
    }
};

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);
    int t;
    if (!(std::cin >> t)) return 0;
    Solution sol;
    for (int i = 0; i < t; i++) {
        long long n;
        if (!(std::cin >> n)) return 0;
        std::string ans = sol.primeFactorisation(n);
        std::cout << ans << "\n";
    }
    return 0;
}
